from collections import defaultdict

def topological_sort(n, edges):
    def dfs(node):
        if node in visited:
            return visited[node]
        visited[node] = -1  # Mark as temporarily visited
        for neighbor in graph[node]:
            if dfs(neighbor) == -1:
                return -1
        visited[node] = 1  # Mark as visited
        order.append(node)
        return 1

    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)

    visited = {}
    order = []
    for node in range(n):
        if dfs(node) == -1:
            return []  # Cycle detected

    return order[::-1]
